class Solution:
    def canReachCorner(self, xCorner: int, yCorner: int, circles: List[List[int]]) -> bool:
        # Check if any circle blocks the entire rectangle
        for x, y, r in circles:
            # Check if the circle blocks the bottom edge (y = 0)
            if y - r <= 0 <= y + r and x - r <= 0 <= x + r:
                continue
            # Check if the circle blocks the top edge (y = yCorner)
            if y - r <= yCorner <= y + r and x - r <= xCorner <= x + r:
                continue
            # Check if the circle blocks the left edge (x = 0)
            if x - r <= 0 <= x + r and y - r <= 0 <= y + r:
                continue
            # Check if the circle blocks the right edge (x = xCorner)
            if x - r <= xCorner <= x + r and y - r <= yCorner <= y + r:
                continue
            # Check if the circle blocks the diagonal (from (0, 0) to (xCorner, yCorner))
            # We check if the circle is close enough to the diagonal
            # The distance from the center of the circle to the diagonal is <= r
            # The diagonal line equation: y = (yCorner / xCorner) * x
            # The distance from (x, y) to this line is |y - (yCorner / xCorner) * x| / sqrt(1 + (yCorner / xCorner)^2)
            # If this distance <= r, the circle blocks the diagonal
            distance = abs(y - (yCorner / xCorner) * x) / ((1 + (yCorner / xCorner)**2)**0.5)
            if distance <= r:
                return False
        return True
